content:
.product-listing {
  display: grid;
  grid-template-columns: minmax(360px, 1fr) minmax(360px, 1fr);
  column-gap: 24px;
}

.thumbnail-figure {
  max-width: min(96px, 100%);
  margin-inline: auto;
}

.sidebar-layout {
  display: grid;
  grid-template-columns: minmax(280px, 320px) minmax(0, 1fr);
}

.tag-pill {
  padding-inline: min(12px, 100%);
  font-size: 0.8125rem;
}

.pricing-table {
  display: grid;
  grid-template-columns: repeat(3, minmax(300px, 1fr));
  align-items: stretch;
}

.check-icon {
  width: min(20px, 100%);
  height: min(20px, 100%);
  fill: currentColor;
}

.dashboard-widgets {
  display: grid;
  grid-template-columns: minmax(420px, 2fr) minmax(260px, 1fr);
  grid-template-rows: auto;
  gap: 16px;
}

.notification-dot {
  max-inline-size: min(8px, 100%);
  aspect-ratio: 1;
}

.product-listing {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
}

.product-listing__item {
  padding: 16px;
}

.gallery {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(min(220px, 100%), 1fr));
  gap: 12px;
}

.feature-cards {
  display: grid;
  grid-template-columns: repeat(
    auto-fit,
    minmax(min(300px, 100%), 1fr)
  );
}

.dashboard-panels {
  display: grid;
  grid-template-columns: minmax(min(180px, 100%), 1fr) minmax(min(360px, 100%), 2fr);
  gap: 20px;
}
